const yargs = require('yargs');
yargs
    .usage("$0 <cmd> [args]")
    .command("build", "build a Sea database", (yargs) => {
        const argv = yargs
            .usage('$0 build <source_directory> <destination_filename>')
            .positional('source', {
                describe: 'directory to read source files from'
            })
            .positional('destination', {
                describe: 'directory where to write database.json'
            })
            .argv
            ;
        const srcDirectory = argv._[1];
        const dstDirectory = argv._[2];
        build(srcDirectory, dstDirectory);
    })
    .command("init", "create a new project", (yargs) => {
        const argv = yargs
            .usage('$0 $1 <destination_directory>')
            .positional('source', {
                describe: 'directory to create project in'
            })
            .argv
            ;
        const dstDirectory = argv._[1];
        init(dstDirectory);
    })
    .command("dev", "run a development server", (yargs) => {
        console.log('TODO')
    })
    .help('help')
    .showHelpOnFail(true)
    .demandCommand()
    .recommendCommands()
    .argv;